return $input.all().map(item => {
  // 1. 원본 텍스트 가져오기 (경로가 맞는지 확인: 필요시 수정)
  let rawText = item.json?.content?.parts?.[0]?.text || 
                item.json?.text || 
                item.json?.output?.[0]?.content?.[0]?.text || 
                "";

  // 2. 가사 관련 불필요한 패턴 제거 (필요에 따라 추가/수정)
  let cleanedText = rawText
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```\s*$/g, "")
    .replace(/\[Lyrics\]:?/gi, "")           // [Lyrics]: 또는 [Lyrics] 제거
    .replace(/\[Verse \d+\]/gi, "")          // [Verse 1], [Verse 2] 등
    .replace(/\[Chorus\]/gi, "")
    .replace(/\[Bridge\]/gi, "")
    .replace(/\[Outro\]/gi, "")
    .replace(/\([^\)]*\)/g, "")              // 괄호 안 내용 제거 (예: (laughs))
    .replace(/\n+/g, " ")                    // 여러 개행 → 한 칸 공백
    .replace(/\r/g, "")                      // \r 제거
    .replace(/\s+/g, " ")                    // 연속 공백 → 한 칸
    .trim();                                 // 앞뒤 공백 제거

  // 3. 빈 문자열이면 fallback (MiniMax 에러 방지)
  if (!cleanedText || cleanedText.length < 1) {
    cleanedText = "이것은 목소리 테스트용 기본 문장입니다. 확인 부탁드려요.";
  }

  // 4. JSON 문자열로 안전하게 사용할 수 있도록 (큰따옴표 이스케이프 등)
  //    → 다음 노드에서 그대로 "{{ $json.cleaned_text }}" 쓰면 됨
  return {
    json: {
      ...item.json,              // 기존 데이터 유지 (voice_id 등 필요시)
      raw_text: rawText,         // 디버깅용 원본 (필요하면 삭제 가능)
      cleaned_text: cleanedText  // 정리된 최종 텍스트
    }
  };
});

// 1. cleaned_text 가져오기
const cleanedText = $json.cleaned_text || $json.raw_text || "";

// 2. 파싱 (JSON 형식 / "A: 내용" 형식 둘 다 대응)
let turns = [];
try {
  const parsed = JSON.parse(cleanedText);
  if (Array.isArray(parsed)) {
    turns = parsed.map(p => ({ speaker: p.speaker, text: p.text }));
  }
} catch(e) {
  const lines = cleanedText.split(/(?=[A-C]:)/).filter(line => line.trim());
  for (const line of lines) {
    const match = line.match(/^([A-C]):\s*(.+)$/s);
    if (match) {
      turns.push({ speaker: match[1], text: match[2].trim() });
    }
  }
}

// 3. voiceMap
const voiceMap = {
  "A": "Roger",
  "B": "Laura",
  "C": "Will"
};

// 4. return
return {
  json: {
    model_id: "eleven_v3",
    output_format: "mp3_44100_128",
    transcript: turns.map(t => ({
      text: t.text,
      voice_id: voiceMap[t.speaker] || "Aria"
    }))
  }
};

