  items.find(item => item.json.Source_text && item.json.Language) ||
  items.find(item => item.json.Source_text) ||
  items[0];

const content     = $('Search records').first().json.Source_text || '';
const rawLanguage = $('Search records').first().json.Language    || '';
const sourceType  = $('Search records').first().json['Source Type'] || 'Text';

// Language 정규화 → Zh 또는 Ko (categoryMap 키와 일치시킴)
let language = rawLanguage.trim().toLowerCase();
if (language.startsWith('zh') || language.includes('중국') || language === 'cn') {
  language = 'Zh';
} else if (language.startsWith('ko') || language.includes('한국') || language === 'kr') {
  language = 'Ko';
} else {
  language = 'Ko';
}

// categoryMap
const categoryMap = {
  'Zh_Text':   8,
  'Zh_Image':  9,
  'Zh_Audio': 14,
  'Zh_Video': 10,
  'Ko_Text':  11,
  'Ko_Image': 12,
  'Ko_Audio': 15,
  'Ko_Video': 13,
};

// 동적 키 생성 (language가 이미 Zh 또는 Ko)
const key = `${language}_${sourceType}`;
const categoryId = categoryMap[key] || 1;

// HTML 생성
const html = `
<h3>원문</h3>
<p style="font-size:28px; font-weight:bold; text-align:center; padding:20px; background:#f5f0e8; border-radius:8px;">${content}</p>
