<img src="${imgUrl}" style="max-width:100%" alt="이미지" />
<h3>오디오</h3>
<audio controls src="${audUrl}"></audio>
<h3>영상</h3>
<video controls src="${vidUrl}" style="max-width:100%"></video>
`;

return [{
  json: {
    html,
    title: content.slice(0, 30),
    categories: [categoryId]
  }
}];

